module.render:
const color = args.color || 'var(--accent-color)';
const start = parseInt(args.start, 10) || 1;
const active = Array.isArray(args.active) ? args.active.map(Number) : [];
const compact = String(args.compact) === 'true';
const showLine = String(args.line === undefined ? 'true' : args.line) !== 'false';
const align = args.align === 'center' ? 'center' : args.align === 'right' ? 'right' : 'left';
const numRaw = parseFloat(args.numsize);
const numsize = Number.isFinite(numRaw) ? Math.max(20, Math.min(60, numRaw)) : 34;
const steps = sections.map((s) => (s || '').trim());
let style = `--st-color:${color};--st-num:${numsize}px;`;
if (align !== 'left') style += `--st-body-align:${align};`;
const cls = 'mdp-mod-steps' + (compact ? ' is-compact' : '') + (showLine ? '' : ' no-line');
let html = `\n\n<div class="${cls}" style="${style}">`;
let n = start - 1;
steps.forEach((s) => {
  if (!s && steps.length > 1) return;
  n += 1;
  const on = active.length === 0 || active.includes(n);
  html += `<div class="mdp-step${on ? ' is-active' : ''}"><div class="mdp-step-num">${n}</div><div class="mdp-step-body">\n\n${s}\n\n</div></div>`;
});
html += `</div>\n\n`;
return html;
